queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?theme_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasThemes ?child ; p:hasBoutique_Hotels ?parent . } GROUP BY ?child }
  ?child p:theme_name ?theme_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Boutique_Hotels } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?theme_name WHERE {
  ?boutique_hotels_themes a :Boutique_Hotels_Themes .
  ?themes a :Themes .
  ?boutique_hotels_themes p:hasThemes ?themes .
  ?boutique_hotels a :Boutique_Hotels .
  ?boutique_hotels_themes p:hasBoutique_Hotels ?boutique_hotels .
  ?boutique_hotels p:name ?name .
  ?themes p:theme_name ?theme_name .
} }
  collective: { SELECT ?theme_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasThemes ?child ; p:hasBoutique_Hotels ?parent . } GROUP BY ?child }
  ?child p:theme_name ?theme_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Boutique_Hotels } }
  FILTER(?nf = ?total)
} }
}
